func newCmdAndroidServiceVrIVrStateCallbacks_OnVrStateChanged() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "on-vr-state-changed",
		Short: "Call OnVrStateChanged(enabled bool)",
		RunE: func(cmd *cobra.Command, args []string) error {
			ctx := context.Background()

			conn, err := cliutil.OpenConn(ctx, cmd)
			if err != nil {
				return err
			}
			defer conn.Close(ctx)

			serviceName, _ := cmd.Flags().GetString("service-name")
			var svc binder.IBinder
			if serviceName != "" {
				svc, err = conn.GetService(ctx, serviceName)
			} else {
				svc, err = cliutil.FindServiceByDescriptor(ctx, conn, "android.service.vr.IVrStateCallbacks")
			}
			if err != nil {
				return err
			}

			svcProxy := vr.NewVrStateCallbacksProxy(svc)

			flagEnabled, err := cmd.Flags().GetBool("enabled")
			if err != nil {
				return fmt.Errorf("reading flag enabled: %w", err)
			}

			err = svcProxy.OnVrStateChanged(ctx, flagEnabled)
			if err != nil {
				return err
			}

			mode, _ := cmd.Root().PersistentFlags().GetString("format")
			f := cliutil.NewFormatter(mode, os.Stdout)
			f.Value("status", "ok")
			return nil
		},
	}

	cmd.Flags().String("service-name", "", "ServiceManager name to use instead of descriptor discovery")
	cmd.Flags().Bool("enabled", false, "enabled (bool)")
	_ = cmd.MarkFlagRequired("enabled")

	return cmd
}
